	// ==================== Builder 内部扩展 API ====================

	/**
	 * @pinkGroup internal-platform
	 */
	export namespace builder {
		/**
		 * 构建任务的运行时状态。
		 */
		export type BuildTaskState = 'waiting' | 'processing' | 'success' | 'failure' | 'cancelled' | 'generated';

		/**
		 * 构建任务信息。
		 */
		export interface IBuildTask {
			/** 任务的唯一标识 ID */
			id: string;
			/** 任务的展示名称 */
			name: string;
			/** 目标构建平台名称 */
			platform: string;
			/** 任务当前的运行时状态 */
			state: BuildTaskState;
			/** 任务当前的进度（通常为 0.0 ~ 1.0） */
			progress: number;
			/** 进度 / 状态文案:processing 时为当前阶段进度,失败时为具体错误原因(含 stage 失败的报错) */
			message?: string;
			/** 失败原因(与失败态的 message 同源);非失败态为 undefined */
			error?: string;
			/** 任务创建时间戳(ms),host 在创建/重启任务时设置 */
			createdAt?: number;
			/** 任务完成时间戳(ms),host 在 success/failure/cancelled/generated 终态时设置 */
			completedAt?: number;
			/** 任务的 build options 快照。所有 UI 需要的衍生信息都从这里读,不在 IBuildTask 上自创字段:
			 *  - 输出目录:`path.join(options.buildPath, options.outputName)`
			 *  - 日志路径:`options.logDest`
			 *  - 阶段链:`options.buildStageGroup` */
			options?: IBuildOptions;
		}

		/** 预览设置 */
		export type IPreviewSettings = _cli.IPreviewSettingsResult;

		/**
		 * 构建进度更新事件数据。
		 */
		export interface IBuildProgress {
			/** 归属构建任务的 ID */
			taskId: string;
			/** 当前的进度百分比值 */
			progress: number;
			/** 进度描述信息 */
			message: string;
		}

		/** 构建选项 */
		export type IBuildOptions = _cli.IBuildCommandOption;

		/** 构建结果数据 */
		export type IBuildResultData = _cli.IBuildResultData;

		/** 单个平台的 Bundle 配置 */
		export type PlatformBundleConfig = _cli.PlatformBundleConfig;

		/** 按平台类型分组的 Bundle 查询配置 */
		export type BundleQueryConfig = _cli.BundleQueryConfig;

		/** Bundle 资源过滤配置 */
		export type BundleFilterConfig = _cli.BundleFilterConfig;

		/** 平台列表项(含 doc / pluginPath,见 queryPlatformConfig) */
		export type PlatformConfigItem = _cli.PlatformConfigItem;

		/** 自定义构建阶段项(IBuildStageItem)— PlatformConfigItem.customBuildStages 的元素类型。 */
		export type IBuildStageItem = _cli.IBuildStageItem;

		/** executeBuildStage 调用参数(dest + platform + 可选 taskName)。 */
		export type IBuildStageOptions = _cli.IBuildStageOptions;

		/** 平台配置编辑页自动渲染数据(common 通用项 + platformOptions 平台项) */
		export type PlatformBuildSchema = _cli.PlatformBuildSchema;

		/**
		 * 查询项目构建配置。
		 * @returns 项目的完整构建配置
		 */
		export function queryBuildConfig(): Thenable<_cli.BuildConfiguration>;

		/**
		 * 根据目标平台查询默认构建配置。
		 * @param platform - 平台名称，如 `'web-mobile'`、`'android'` 等
		 * @returns 该平台的默认配置键值对
		 */
		export function queryDefaultBuildConfigByPlatform(platform: string): Thenable<Record<string, any>>;

		/**
		 * 获取预览设置。
		 * @returns 预览相关的配置信息
		 */
		export function getPreviewSettings(): Thenable<_cli.IPreviewSettingsResult>;

		/**
		 * 执行构建（同步等待完成）。
		 * @param platform - 目标平台名称
		 * @param options - 可选的构建选项
		 * @returns 构建结果数据
		 */
		export function build(platform: string, options?: _cli.IBuildCommandOption): Promise<IBuildResultData>;

		/**
		 * 添加构建任务（异步，不等待完成）。
		 * @param options - 构建选项
		 * @returns 创建的构建任务信息
		 */
		export function addBuildTask(options: _cli.IBuildCommandOption): Promise<IBuildTask>;

		/**
		 * 批量添加构建任务（异步，不等待完成）。「全部构建」场景一次下发多个平台,
		 * 避免 per-platform 各发一次 IPC;内部串行入队,一个个执行。
		 * @param optionsList - 各平台的构建选项数组
		 * @returns 创建的构建任务信息数组(顺序与入参一致)
		 */
		export function addBuildTasks(optionsList: _cli.IBuildCommandOption[]): Promise<IBuildTask[]>;

		/**
		 * 重新执行指定的构建任务。
		 * @param taskId - 构建任务 ID
		 */
		export function rebuild(taskId: string): Promise<void>;

		/**
		 * 中断指定的构建任务。
		 * @param taskId - 构建任务 ID
		 */
		export function abortTask(taskId: string): Promise<void>;

		/**
		 * 移除构建任务。
		 * @param taskId - 构建任务 ID
		 * @param removeFiles - 是否同时删除构建产物文件，默认 `false`
		 */
		export function removeBuildTask(taskId: string, removeFiles?: boolean): Promise<void>;

		/**
		 * 更新指定构建任务的构建选项。
		 * @param taskId - 构建任务 ID
		 * @param options - 新的构建选项
		 */
		export function updateOptions(taskId: string, options: _cli.IBuildCommandOption): Promise<void>;

		/**
		 * 清理构建缓存。
		 * @param options - 清理范围
		 *   - `'project'` — 仅清理当前项目缓存
		 *   - `'global'`  — 仅清理全局缓存
		 *   - `'all'`     — 清理全部缓存
		 */
		export function clearCache(options: { scope: 'project' | 'global' | 'all' }): Promise<void>;

		/**
		 * 获取所有构建任务的快照。
		 * @returns 当前所有构建任务列表
		 */
		export function getTasks(): Thenable<IBuildTask[]>;

		/**
		 * 获取当前支持的构建平台列表。
		 * @returns 平台名称列表，如 `['web-mobile', 'android', 'ios', ...]`
		 */
		export function getSupportedPlatforms(): Thenable<string[]>;

		/**
		 * 查询平台配置（用于渲染平台列表）。
		 * @returns 各平台的配置信息数组(含 displayName 已翻译、doc 文档相对地址、pluginPath 插件目录)
		 */
		export function queryPlatformConfig(): Thenable<PlatformConfigItem[]>;

		/**
		 * 为指定平台创建构建模板:把该平台声明的模板文件复制到项目 `build-templates` 目录,
		 * 并维护 `templates-version.json` 版本记录。
		 * @param nameOrPlatform 平台 id(如 'web-mobile';即 PlatformConfigItem.platform),
		 *                       或模板 label;若该平台未声明构建模板则为 no-op。
		 */
		export function createBuildTemplate(nameOrPlatform: string): Thenable<void>;

		/**
		 * 在已存在的 build 任务上执行 customBuildStage(如 generate / upload)。stage 进度回写到该任务,
		 * UI 通过现有 onTaskChange 事件接收;链跑完后任务状态 -> 'generated'。
		 * @param taskId   已存在的 build 任务 id(由 addBuildTask 返回);未找到 → 返回 { ok: false }
		 * @param stageName  customBuildStages 中某 stage 的 name
		 * @param options  IBuildStageOptions(dest + platform)+ 可选 nextStages 让 CLI 按顺序串跑
		 */
		export function executeBuildStage(taskId: string, stageName: string, options: IBuildStageOptions & { nextStages?: string[] }): Thenable<{ ok: boolean; reason?: string }>;

		/**
		 * 查询某平台配置编辑页的自动渲染数据。
		 * @param platform 平台 id,如 'wechatgame'
		 * @returns `{ common, platformOptions }`,值为 IBuilderConfigItem(type/default/label/enum/items + verifyRules 等)
		 */
		export function getPlatformBuildSchema(platform: string): Thenable<PlatformBuildSchema>;

		/**
		 * 校验单个构建配置项;返回 BuildCheckResult(error 空即通过,含 level / 建议修正值 newValue)。
		 * @param platform 平台 id;key 字段名;value 当前值;options 当前整份构建配置(供跨字段规则参考)
		 */
		export function checkBuildOption(platform: string, key: string, value: unknown, options: _cli.IBuildTaskOption): Thenable<_cli.BuildCheckResult>;

		/**
		 * 批量校验整份构建配置(打开配置页时一次性校验,标出既有错误),返回 字段名 -> 结果。
		 */
		export function checkBuildOptions(platform: string, options: _cli.IBuildTaskOption): Thenable<Record<string, _cli.BuildCheckResult>>;

		/**
		 * 查询 Asset Bundle 配置（用于渲染 Bundle Config 面板）。
		 * 返回按平台类型（native/web/miniGame）分组的查询配置，
		 * 包含各平台支持的 compressionType 等信息。
		 * @returns 按平台类型分组的 BundleQueryConfig
		 */
		export function queryBundleConfig(): Thenable<Record<string, BundleQueryConfig>>;

		/**
		 * 查询纹理压缩配置（用于渲染纹理压缩面板）。
		 * 返回完整渲染所需数据：configGroups、textureFormatConfigs、formatsInfo、defaultSupport、platformRenderConfigs。
		 */
		export function queryTextureCompressConfig(): Thenable<Record<string, any>>;

		/** AutoAtlas 打包参数（透传给 cocos-cli 的 packAutoAtlas） */
		export type AutoAtlasPackOptions = _cli.IPackOptions;

		/** AutoAtlas 预览结果 */
		export type AutoAtlasPreviewResult = _cli.PreviewPackResult;

		/**
		 * 对 auto-atlas (.pac) 资源执行预览打包。强制 mode='preview'，不产生构建产物。
		 * 用于资源编辑面板的「预览」按钮。
		 * @param pacUuid - auto-atlas 资源 uuid
		 * @param options - 打包参数（来自资源 userData），不传则使用资源默认配置
		 * @returns 打包结果；资源不存在或打包失败时返回 null
		 */
		export function packAutoAtlas(
			pacUuid: string,
			options?: Partial<AutoAtlasPackOptions>,
		): Thenable<AutoAtlasPreviewResult | null>;

		/**
		 * 查询指定 auto-atlas 资源上一次预览/构建产出的缓存结果。
		 * 面板挂载时调用，避免每次重新打包。
		 * @param pacUuid - auto-atlas 资源 uuid
		 * @returns 缓存的打包结果；无缓存时返回 null
		 */
		export function queryAutoAtlasFileCache(pacUuid: string): Thenable<AutoAtlasPreviewResult | null>;

		/**
		 * 查询指定 Bundle 文件夹中实际会被打包的资源列表。
		 * @param uuid - Bundle 文件夹的 uuid
		 * @param bundleFilterConfig - 可选的过滤配置，不传则使用 Bundle 自身的过滤配置
		 * @returns 符合条件的资源 URL 列表
		 */
		export function queryAssetsInBundle(uuid: string, bundleFilterConfig?: BundleFilterConfig[]): Thenable<string[]>;

		/**
		 * 根据平台查询详细构建配置元数据（用于渲染构建表单）。
		 * @param platform - 平台名称
		 * @returns 该平台的构建配置元数据
		 */
		export function queryBuildConfigByPlatform(platform: string): Thenable<Record<string, any>>;
	}


	// ==================== BaseConfig 内部扩展 API ====================

	export namespace baseConfig {
		/**
		 * 本地配置（`~/.pink/api-config.json`）。
		 * 用于覆盖默认的在线配置。
		 */
		export interface ILocalConfig {
			/** 功能开关 */
			feature?: {
				/** 是否启用 PinK 模块 */
				pinkModule: boolean;
				/** 常驻显示 Test Helper 入口 */
				testHelper: boolean;
				/** 是否启用动画编辑器 */
				animationEditor: boolean;
			};
			/** 运行环境 */
			env?: 'dev' | 'fat' | 'prod';
			/** 构建容器首页拆分页地址(本地覆盖,用于本地加载测试) */
			builderHome?: { url?: string; enabled?: boolean; devOtaZipUrl?: string };
			/**
			 * 构建面板平台目录本地覆盖(可见性 + 分组 + 排序)。优先级最高:本地 > 服务端下发 > 本地兜底。
			 * 便于本地调试平台显隐 / 分组 / 排序,直接写在 `~/.pink/api-config.json`,无需依赖服务端下发。
			 */
			builderPlatforms?: IBuilderPlatformCatalogItem[];
			/** 构建面板分类容器目录本地覆盖(每项一个侧边 tab)。优先级最高:本地 > 服务端下发 > 内置兜底。 */
			builderCategories?: IBuilderCategory[];
		}

		/**
		 * 合并后的基础配置（本地 > 在线 > 默认）。
		 */
		export interface IBaseConfig {
			/** API 地址集合 */
			api: {
				/** 网关地址 */
				gate: string;
				/** API 地址 */
				api: string;
				/** 认证服务地址 */
				auth: string;
				/** 遥测上报地址 */
				telemetry: string;
			};
			/** 功能开关 */
			feature: {
				/** 是否启用 PinK 模块 */
				pinkModule: boolean;
				/** 常驻显示 Test Helper 入口 */
				testHelper: boolean;
				/** 是否启用动画编辑器 */
				animationEditor: boolean;
			};
			/** 当前运行环境 */
			env: 'dev' | 'fat' | 'prod';
			/**
			 * 构建面板平台分组的**覆盖**项(分组 + 精选 + 排序)。默认来自各平台插件注册（contributes.pinkBuilder）;
			 * 此列表按平台 id 覆盖,优先级 本地（`~/.pink/api-config.json`）> 服务端下发 > 空（不覆盖）。
			 */
			builderPlatforms: IBuilderPlatformCatalogItem[];
			/** 构建面板分类容器目录(每项一个侧边 tab)。优先级:本地 > 服务端下发 > 内置兜底(game/native)。 */
			builderCategories: IBuilderCategory[];
			/**
			 * 构建容器「首页」拆分页:仅当 enabled=true 且 url 有值时,容器才经 iframe 加载该地址作首页;
			 * 否则(默认)用内置默认首页。可经本地配置(`~/.pink/api-config.json`)覆盖,用于本地加载测试。
			 */
			builderHome?: { url?: string; enabled?: boolean; allowedHosts?: string[]; devOtaZipUrl?: string };
		}

		/**
		 * 构建面板「平台目录」单项:需要展示的平台 id 及其区域归类、精选标记与排序。
		 */
		export interface IBuilderPlatformCatalogItem {
			/** 平台 id,对应 `pink.builder.queryPlatformConfig().platform` */
			id: string;
			/** 区域归类(如 domestic / overseas / ai)。省略 = 不进任何区域 Tab(如仅做精选、区域尚未对外) */
			group?: string;
			/** 是否进「精选」Tab;与 group 正交(可同时精选 + 属某区域) */
			featured?: boolean;
			/** 组内显示顺序(升序;缺省排最后) */
			order?: number;
			/** 分类容器归属(对应 platform.category,如 'game' / 'native')。覆盖平台插件 contributes.pinkBuilder.category。 */
			category?: string;
		}

		/** 构建面板分类容器单项:每项一个左侧 activity container(侧边 tab)。 */
		export interface IBuilderCategory {
			id: string;
			title: string;
			icon: string;
			activeIcon?: string;
			order?: number;
		}

		/**
		 * 获取合并后的配置（带缓存）。
		 * 优先级：本地 > 在线 > 默认。
		 *
		 * 开放给平台 host(internal-platform 分组):平台插件可据此读取当前环境(`env`)等基础配置。
		 * @pinkGroup internal-platform
		 */
		export function getConfig(): Thenable<IBaseConfig>;
	}


